import React from 'react';

const Navbar = () => {
  return (
    <header>
      <nav className="navigasi" aria-label="Main Navigation">
        <div className="logo-navigasi">
          Putra<span>.</span>
        </div>
        <ul className="tautan-navigasi">
          <li><a href="#tentang">About</a></li>
          <li><a href="#pengalaman">Experience</a></li>
          <li><a href="#proyek">Projects</a></li>
          <li><a href="#keahlian">Skills</a></li>
          <li><a href="#pendidikan">Education</a></li>
          <li><a href="#sertifikasi">Certifications</a></li>
          <li><a href="#organisasi">Organizations</a></li>
        </ul>
        <a href="#kontak" className="tombol">Contact Me</a>
      </nav>
    </header>
  );
};

export default Navbar;
